const appt = $input.first().json;
const startTime = new Date(appt.start_time);
const now = new Date();
const diffHours = (startTime - now) / (1000 * 60 * 60);

const is24h = diffHours >= 23 && diffHours <= 25;
const is1h = diffHours >= 0.9 && diffHours <= 1.1;

const lang = appt.language_preference || 'en';

const messages = {
  en: {
    reminder_24h: `Hi ${appt.customer_name}! 👋\n\nReminder: You have a *${appt.service_name}* appointment tomorrow with ${appt.staff_name}.\n\n📅 ${startTime.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}\n⏰ ${startTime.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', timeZone: appt.timezone })}\n\nNeed to reschedule? Just reply here! 💙`,
    reminder_1h: `Hi ${appt.customer_name}! ⏰\n\nYour *${appt.service_name}* appointment is in *1 hour*!\n\nSee you soon at the salon! 💅`
  },
  es: {
    reminder_24h: `¡Hola ${appt.customer_name}! 👋\n\nRecordatorio: Tienes una cita de *${appt.service_name}* mañana con ${appt.staff_name}.\n\n📅 ${startTime.toLocaleDateString('es', { weekday: 'long', month: 'long', day: 'numeric' })}\n⏰ ${startTime.toLocaleTimeString('es', { hour: '2-digit', minute: '2-digit', timeZone: appt.timezone })}\n\n¿Necesitas reprogramar? ¡Solo responde aquí! 💙`,
    reminder_1h: `¡Hola ${appt.customer_name}! ⏰\n\n¡Tu cita de *${appt.service_name}* es en *1 hora*!\n\n¡Nos vemos pronto! 💅`
  }
};

const msgSet = messages[lang] || messages['en'];
const messageText = is24h ? msgSet.reminder_24h : (is1h ? msgSet.reminder_1h : null);

if (!messageText) {
  return [{ json: { skip: true } }];
}

return [{
  json: {
    ...appt,
    message: messageText,
    reminder_type: is24h ? '24h' : '1h'
  }
}];
